#include <iostream>
#include <string>
#include <vector>
#include <algorithm>

bool isPalindrome(const std::string& s) {
    if (s.empty()) {
        return true;
    }

    std::string reversed_str_manual;
    reversed_str_manual.reserve(s.length());

    for (int i = s.length() - 1; i >= 0; --i) {
        reversed_str_manual += s[i];
    }

    return s == reversed_str_manual;
}

int main() {
    std::string line;
    while (std::getline(std::cin, line)) {
        if (isPalindrome(line)) {
            std::cout << "Yes, \"" << line << "\" is a palindrome." << std::endl;
        } else {
            std::cout << "No, \"" << line << "\" is not a palindrome." << std::endl;
        }
    }
    return 0;
}
